import { strict as assert } from 'assert';
import worker from './index.js';
import type { Env } from './types.js';

type WorkerModule = {
  fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response>;
};

const handler = worker as WorkerModule;

const testExecutionContext = {
  waitUntil() {},
  passThroughOnException() {},
} as unknown as ExecutionContext;

export async function runIndexTests(): Promise<void> {
  const response = await handler.fetch(
    new Request('https://example.com/api/workspaces', {
      method: 'POST',
      headers: {
        'Content-Length': String(5 * 1024 * 1024 + 1),
      },
    }),
    {
      NIMBUS_HOSTED: 'false',
    } as Env,
    testExecutionContext
  );

  assert.equal(response.status, 413);
  const payload = (await response.json()) as Record<string, unknown>;
  assert.equal(payload.error, 'Request body too large');
  assert.equal(payload.code, 'request_too_large');
}

